package com.promonts.dto;import com.promonts.domain.workspace.Workspace;import lombok.*;import java.time.LocalDateTime;@Data @NoArgsConstructor @AllArgsConstructor @Builder public class WorkspaceListResponse{private Long id;private String name;private String courseName;private LocalDateTime lastAccessedAt;public static WorkspaceListResponse from(Workspace workspace){String courseName=null;if(workspace.getCourse()!=null){courseName=workspace.getCourse().getName();}return WorkspaceListResponse.builder().id(workspace.getId()).name(workspace.getName()).courseName(courseName).lastAccessedAt(workspace.getLastAccessedAt()).build();}}
